import json
import os
from typing import Dict, Any, List


REQUIRED_SUMMARY_KEYS = [
    "service_introduction",
    "user_rights",
    "data_and_privacy",
    "payment_and_refund",
    "limitation_of_liability",
    "dispute_resolution",
    "other_important_terms"
]

# Use the output generated by test_pipeline.py or evaluation_runner.py
# Change this path if needed.
MODEL_OUTPUT_FILE = "google_tos_example_evaluation_output.json"


def load_model_output(path: str) -> Dict[str, Any]:
    """
    Load a saved pipeline output JSON file.
    """
    if not os.path.exists(path):
        raise FileNotFoundError(f"Output file not found: {path}")

    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def check_summary_accuracy(result: Dict[str, Any]) -> Dict[str, Any]:
    """
    Evaluate summary quality using lightweight heuristics.

    This does not verify legal correctness.
    Instead, it checks whether:
    - all required summary fields exist
    - fields are not empty
    - fields are not mostly placeholders
    - fields contain a reasonable amount of information
    """
    summary = result.get("summary", {})
    field_results = {}
    total_score = 0

    for key in REQUIRED_SUMMARY_KEYS:
        text = summary.get(key, "").strip()

        # Scoring heuristic:
        # 0 = missing
        # 1 = placeholder / almost empty
        # 2 = short but present
        # 3 = reasonably informative
        if not text:
            score = 0
        elif text in ["Not found in this section.", "Not found in the provided text."]:
            score = 1
        elif len(text.split()) < 12:
            score = 2
        else:
            score = 3

        field_results[key] = {
            "score": score,
            "word_count": len(text.split()),
            "preview": text[:120]
        }
        total_score += score

    max_score = len(REQUIRED_SUMMARY_KEYS) * 3
    normalized_score = round(total_score / max_score, 3)

    return {
        "task": "Check summary accuracy",
        "field_results": field_results,
        "total_score": total_score,
        "max_score": max_score,
        "normalized_score": normalized_score,
        "manual_review_template": {
            "summary_accuracy_1_to_5": None,
            "summary_coverage_1_to_5": None,
            "reviewer_notes": ""
        }
    }


def check_risk_highlight_usefulness(result: Dict[str, Any]) -> Dict[str, Any]:
    """
    Evaluate risk highlight usefulness using lightweight heuristics.

    This checks whether:
    - risk highlights exist
    - they are not empty
    - they are sufficiently detailed
    - they are likely useful to a normal user
    """
    risks = result.get("risk_highlights", [])

    detailed_count = 0
    vague_count = 0
    empty_count = 0

    risk_details: List[Dict[str, Any]] = []

    for risk in risks:
        text = risk.strip()

        if not text:
            empty_count += 1
            score = 0
        elif len(text.split()) < 6:
            vague_count += 1
            score = 1
        elif len(text.split()) < 12:
            detailed_count += 1
            score = 2
        else:
            detailed_count += 1
            score = 3

        risk_details.append({
            "text": text,
            "score": score,
            "word_count": len(text.split())
        })

    if not risks:
        usefulness_score = 0
    elif detailed_count == 0:
        usefulness_score = 1
    elif detailed_count < len(risks) / 2:
        usefulness_score = 2
    else:
        usefulness_score = 3

    return {
        "task": "Check risk-highlight usefulness",
        "risk_count": len(risks),
        "detailed_count": detailed_count,
        "vague_count": vague_count,
        "empty_count": empty_count,
        "usefulness_score": usefulness_score,
        "risk_details": risk_details,
        "manual_review_template": {
            "risk_highlight_usefulness_1_to_5": None,
            "reviewer_notes": ""
        }
    }


def main():
    result = load_model_output(MODEL_OUTPUT_FILE)

    summary_check = check_summary_accuracy(result)
    risk_check = check_risk_highlight_usefulness(result)

    final_report = {
        "source_output_file": MODEL_OUTPUT_FILE,
        "summary_accuracy_check": summary_check,
        "risk_highlight_usefulness_check": risk_check
    }

    print("Output Quality Check:")
    print(json.dumps(final_report, indent=2, ensure_ascii=False))

    with open("output_quality_checks.json", "w", encoding="utf-8") as f:
        json.dump(final_report, f, indent=2, ensure_ascii=False)

    print("\nSaved results to: output_quality_checks.json")


if __name__ == "__main__":
    main()